using System.Linq;
namespace GlitchCompiler.Progression { public sealed class PlayerProfileManager { private readonly SaveDataRepository repository; public PlayerData Data { get; private set; } public PlayerProfileManager(SaveDataRepository value){repository=value;} public void Load(){Data=repository.Load();} public bool IsUnlocked(int index)=>Data!=null&&index<=Data.HighestUnlocked; public void RecordWin(string id,int index,float match,float seconds){var record=Data.Records.FirstOrDefault(x=>x.LevelId==id);if(record==null){record=new LevelRecord{LevelId=id,BestMatch=match,BestSeconds=seconds};Data.Records.Add(record);}else{record.BestMatch=System.Math.Max(record.BestMatch,match);if(record.BestSeconds<=0||seconds<record.BestSeconds)record.BestSeconds=seconds;}Data.HighestUnlocked=System.Math.Max(Data.HighestUnlocked,index+1);repository.Save(Data);} } }
